const book = {
  title: 'The Great Gatsby',
  author: 'F. Scott Fitzgerald',
  year: 1925,
  publisher: 'Scribner'
};

function displayBookInfo({ title, author, year, publisher = 'unknown' }) {
  console.log(`${title} by ${author} was published in ${year} by ${publisher}.`);
}

displayBookInfo(book);

const valuesArray = [ ...Object.values(book) ];
console.log(valuesArray);
